d3.csv("https://raw.githubusercontent.com/holtzy/data_to_viz/master/Example_dataset/7_OneCatOneNum.csv", function(data) {

  // Use d3-force algorithm to find a position for each entity
  var simulation = d3.forceSimulation(data)
      .force("x", d3.forceX(function(d) { return x(d.Value); }).strength(5))
      .force("y", d3.forceY(height / 2))
      .force("collide", d3.forceCollide(6))
      .stop();
  for (var i = 0; i < 300; ++i) simulation.tick();

  // prepare data
  var cell = svg.append("g")
    .selectAll("g")
    .data(d3.voronoi()
      .extent([[-margin.left, -margin.top], [width + margin.right, height + margin.top]])
      .x(function(d) { return d.x; })
      .y(function(d) { return d.y; })
      .polygons(data)
    )
    .enter()
    .append("g");

  // Finally append the circles
  cell.append("circle")
        .attr("r", 5)
        .attr("cx", function(d) { return d.data.x; })
        .attr("cy", function(d) { return d.data.y; });

})

